import type { FC } from 'react';
import { useCallback, useEffect, useRef, useState } from 'react';
import { cx } from '@/utils/cx';
import { Button } from '@/components/atoms/Button';
import type { WithDataId } from '@/types/withDataId';
import {
  AvatarNotification,
  IconNotification,
  ImageNotification,
  type NotificationColor,
} from '@/vendor/untitled-ui/application/notifications/notifications';

/** Semantic color applied to the toast icon and featured-icon container. */
export type ToastColor = NotificationColor;

/** Action button that triggers a callback when clicked. */
export type ToastActionButton = {
  /** Label displayed on the button. */
  text: string;
  /** Handler invoked when the button is clicked. */
  onClick: () => void;
};

/** Link button that navigates to a URL (renders as an anchor). */
export type ToastLinkButton = {
  /** Label displayed on the button. */
  text: string;
  /** URL the button navigates to. */
  url: string;
};

/** A custom action button rendered inside the toast. */
export type ToastButton = ToastActionButton | ToastLinkButton;

/** Controls the layout of the icon/avatar and content. */
export type ToastLayout = 'inline' | 'stacked';

/** Sonner-compatible position for the toast within the viewport. */
export type ToastPosition =
  | 'top-left'
  | 'top-right'
  | 'bottom-left'
  | 'bottom-right';

type BaseProps = {
  /** Primary heading of the toast. */
  title: string;
  /** Supporting text displayed below the title. */
  description?: string;
  /** Label for the primary action button. */
  confirmLabel?: string;
  /** Label for the dismiss action button. Defaults to "Dismiss". */
  dismissLabel?: string;
  /** Hides the dismiss button, leaving only the confirm action. */
  hideDismissLabel?: boolean;
  /** Additional action buttons rendered inline with dismiss/confirm. */
  buttons?: ToastButton[];
  /** Callback fired when the confirm button is clicked. */
  onConfirm?: () => void;
  /** Callback fired when the toast is closed (dismiss, close button, or auto-close). */
  onClose?: () => void;
  /** Whether the toast automatically closes after a delay. @default true */
  autoClose?: boolean;
  /** Time in milliseconds before the toast auto-closes. @default 5000 */
  autoCloseDelay?: number;
  /** Position of the toast within the viewport. @default 'bottom-right' */
  position?: ToastPosition;
  /** Controls the layout of the icon/avatar and content. `'inline'` places them side by side, `'stacked'` keeps them in a column. @default 'inline' */
  layout?: ToastLayout;
  /** Custom class name applied to the notification root element. */
  className?: string;
  /** Custom width for the toast. @default '400px' */
  width?: string;
};

type IconToastProps = BaseProps & {
  /** Renders the icon notification variant. */
  render: 'icon';
  /** Custom icon component or element displayed in the featured-icon slot. */
  icon?: FC<{ className?: string }>;
  /** Semantic color of the featured icon. @default 'default' */
  color?: ToastColor;
  /** Progress value (0–100) shown as a progress bar below the description. */
  progress?: number;
  /** Custom formatter for the progress label. Receives the current value and returns a display string. */
  progressFormatter?: (value: number) => string;
};

type ImageToastProps = BaseProps & {
  /** Renders the image notification variant. */
  render: 'image';
  /** Image source used on mobile viewports. */
  imageMobile: string;
  /** Image source used on desktop viewports. Falls back to `imageMobile`. */
  imageDesktop?: string;
};

type AvatarToastProps = BaseProps & {
  /** Renders the avatar notification variant. */
  render: 'avatar';
  /** Display name shown next to the avatar. */
  name: string;
  /** Avatar image URL. */
  avatar: string;
  /** Timestamp or relative date label (e.g. "5 min ago"). */
  date?: string;
};

export type ToastProps = (IconToastProps | ImageToastProps | AvatarToastProps) &
  WithDataId;

const DEFAULT_AUTO_CLOSE_DELAY = 5000;
const EXIT_ANIMATION_DURATION = 200;

export const Toast = ({
  autoClose = true,
  autoCloseDelay = DEFAULT_AUTO_CLOSE_DELAY,
  onClose,
  onConfirm,
  'data-id': dataId,
  ...props
}: ToastProps) => {
  const ref = useRef<HTMLDivElement>(null);
  const timer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const [exiting, setExiting] = useState(false);

  const exitTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  const close = useCallback(() => {
    setExiting(true);
    exitTimer.current = setTimeout(() => {
      onClose?.();
    }, EXIT_ANIMATION_DURATION);
  }, [onClose]);

  const startAutoClose = useCallback(() => {
    if (!autoClose) return;
    if (timer.current) clearTimeout(timer.current);
    timer.current = setTimeout(() => {
      close();
    }, autoCloseDelay);
  }, [autoClose, autoCloseDelay, close]);

  const resetAutoClose = useCallback(() => {
    if (timer.current) clearTimeout(timer.current);
  }, []);

  useEffect(() => {
    startAutoClose();
    return () => {
      resetAutoClose();
      if (exitTimer.current) clearTimeout(exitTimer.current);
    };
  }, [startAutoClose, resetAutoClose]);

  const shared = {
    onClose: close,
    onConfirm: () => {
      onConfirm?.();
      close();
    },
  };

  const layoutClassName = cx(
    props.className,
    props.layout === 'stacked' && 'xs:flex-col',
  );

  const customButtons = props.buttons?.map((button, index) =>
    'url' in button ? (
      <Button
        key={`${button.text}-${index}`}
        data-id={`${dataId}-toast-button-${index}`}
        size="sm"
        color="link-color"
        href={button.url}
      >
        {button.text}
      </Button>
    ) : (
      <Button
        key={`${button.text}-${index}`}
        data-id={`${dataId}-toast-button-${index}`}
        size="sm"
        color="link-color"
        onClick={() => {
          button.onClick();
          close();
        }}
      >
        {button.text}
      </Button>
    ),
  );

  const renderToast = () => {
    switch (props.render) {
      case 'icon':
        return (
          <IconNotification
            title={props.title}
            description={props.description ?? ''}
            className={layoutClassName}
            width={props.width}
            confirmLabel={props.confirmLabel}
            dismissLabel={props.dismissLabel}
            hideDismissLabel={props.hideDismissLabel}
            icon={props.icon}
            color={props.color}
            progress={props.progress}
            progressFormatter={props.progressFormatter}
            data-id={dataId}
            {...shared}
          >
            {customButtons}
          </IconNotification>
        );

      case 'image':
        return (
          <ImageNotification
            title={props.title}
            description={props.description ?? ''}
            className={layoutClassName}
            confirmLabel={props.confirmLabel ?? ''}
            dismissLabel={props.dismissLabel}
            hideDismissLabel={props.hideDismissLabel}
            imageMobile={props.imageMobile}
            imageDesktop={props.imageDesktop ?? props.imageMobile}
            data-id={dataId}
            {...shared}
          >
            {customButtons}
          </ImageNotification>
        );

      case 'avatar':
        return (
          <AvatarNotification
            name={props.name}
            content={props.description ?? ''}
            className={layoutClassName}
            width={props.width}
            avatar={props.avatar}
            date={props.date ?? ''}
            confirmLabel={props.confirmLabel ?? ''}
            dismissLabel={props.dismissLabel}
            hideDismissLabel={props.hideDismissLabel}
            data-id={dataId}
            {...shared}
          >
            {customButtons}
          </AvatarNotification>
        );

      default:
        return null;
    }
  };

  return (
    <div
      ref={ref}
      className={cx(
        exiting
          ? 'duration-200 ease-in animate-out fade-out slide-out-to-top-2'
          : 'duration-200 ease-out animate-in fade-in slide-in-from-bottom-2',
      )}
      onMouseEnter={resetAutoClose}
      onMouseLeave={startAutoClose}
    >
      {renderToast()}
    </div>
  );
};
